<?php
namespace App\Domain\Equipment;use App\Domain\Equipment\Data\CharacterEquipmentMutationResult;use App\Domain\Equipment\Exceptions\InsufficientEquipmentInventoryCapacityException;use App\Domain\Inventory\Capacity\PendingRewardCapacityService;use App\Domain\Inventory\Instances\ItemInstanceEventService;use App\Domain\Inventory\Instances\ItemInstanceStatus;use App\Models\Character;use App\Models\CharacterClass;use App\Models\CharacterEquipment;use App\Models\CharacterItem;use App\Models\Item;use App\Models\ItemInstance;use Carbon\CarbonImmutable;use Illuminate\Database\Eloquent\ModelNotFoundException;use Illuminate\Support\Facades\DB;use Illuminate\Support\Str;use InvalidArgumentException;use RuntimeException;
final class CharacterEquipmentService{private $items;private $events;private $capacity;private $eligibility;public function __construct(EquippableItemValidator $items,ItemInstanceEventService $events,PendingRewardCapacityService $capacity,EquipmentEligibilityService $eligibility){$this->items=$items;$this->events=$events;$this->capacity=$capacity;$this->eligibility=$eligibility;}public function equip(Character $character,$uuid,$slot){CharacterEquipmentSlot::assertValid($slot);return DB::transaction(function()use($character,$uuid,$slot){list($locked,$class,$inventory,$instances,$equipment,$catalog)=$this->lockState($character);$this->assertSynchronized($locked,$instances,$equipment,$catalog);$target=$instances->firstWhere('uuid',$uuid);if(!$target)throw(new ModelNotFoundException())->setModel(ItemInstance::class);$targetRow=$equipment->firstWhere('item_instance_id',$target->id);if($target->status===ItemInstanceStatus::EQUIPPED){if($targetRow&&$targetRow->slot===$slot)return new CharacterEquipmentMutationResult(false,null);throw new InvalidArgumentException('ItemInstance is already equipped in another slot.');}if($target->status!==ItemInstanceStatus::AVAILABLE||$targetRow)throw new RuntimeException('Inconsistent ItemInstance equipment state.');$newItem=$catalog->get($target->item_id);if(!$newItem)throw new InvalidArgumentException('Item cannot be equipped.');$allowed=CharacterClass::query()->select('character_classes.*')->join('character_class_item','character_class_item.character_class_id','=','character_classes.id')->where('character_class_item.item_id',$newItem->id)->orderBy('character_classes.id')->lockForUpdate()->get();$eligibility=$this->eligibility->evaluate($locked,$target,$newItem,$slot,$allowed,$class);if(!$eligibility->eligible())throw new InvalidArgumentException($eligibility->message());$current=$equipment->firstWhere('slot',$slot);$old=$current?$instances->firstWhere('id',$current->item_instance_id):null;$oldItem=$old?$catalog->get($old->item_id):null;if($old&&(!$oldItem||$old->status!==ItemInstanceStatus::EQUIPPED||(int)$old->character_id!==(int)$locked->id))throw new RuntimeException('Inconsistent equipped ItemInstance.');$operation=(string)Str::uuid();$now=CarbonImmutable::now();if($old){$old->status=ItemInstanceStatus::AVAILABLE;$old->save();$current->item_instance_id=$target->id;$current->equipped_at=$now;$current->save();$this->events->appendUnequipped($old,$locked,$oldItem,$slot,$operation,$now);}else CharacterEquipment::create(['character_id'=>$locked->id,'slot'=>$slot,'item_instance_id'=>$target->id,'equipped_at'=>$now]);$target->status=ItemInstanceStatus::EQUIPPED;$target->save();$this->events->appendEquipped($target,$locked,$newItem,$slot,$operation,$now);return new CharacterEquipmentMutationResult(true,$operation);},3);}public function unequip(Character $character,$slot){CharacterEquipmentSlot::assertValid($slot);return DB::transaction(function()use($character,$slot){list($locked,$class,$inventory,$instances,$equipment,$catalog)=$this->lockState($character);$this->assertSynchronized($locked,$instances,$equipment,$catalog);$row=$equipment->firstWhere('slot',$slot);if(!$row)return new CharacterEquipmentMutationResult(false,null);$instance=$instances->firstWhere('id',$row->item_instance_id);$item=$instance?$catalog->get($instance->item_id):null;if(!$instance||!$item||$instance->status!==ItemInstanceStatus::EQUIPPED)throw new RuntimeException('Inconsistent equipped ItemInstance.');$physical=$this->capacity->fromLoadedState($locked,$inventory,collect(),$catalog,CarbonImmutable::now(),$instances)->toArray();if($physical['current_free_slots']<1)throw new InsufficientEquipmentInventoryCapacityException();$operation=(string)Str::uuid();$now=CarbonImmutable::now();$row->delete();$instance->status=ItemInstanceStatus::AVAILABLE;$instance->save();$this->events->appendUnequipped($instance,$locked,$item,$slot,$operation,$now);return new CharacterEquipmentMutationResult(true,$operation);},3);}private function lockState(Character $character){$locked=Character::whereKey($character->id)->lockForUpdate()->firstOrFail();$class=$locked->character_class_id?CharacterClass::whereKey($locked->character_class_id)->lockForUpdate()->first():null;$inventory=CharacterItem::where('character_id',$locked->id)->orderBy('id')->lockForUpdate()->get();$instances=ItemInstance::where('character_id',$locked->id)->orderBy('id')->lockForUpdate()->get();$equipment=CharacterEquipment::where('character_id',$locked->id)->orderBy('id')->lockForUpdate()->get();$itemIds=$inventory->pluck('item_id')->merge($instances->pluck('item_id'))->unique()->sort()->values();$catalog=Item::whereIn('id',$itemIds)->orderBy('id')->lockForUpdate()->get()->keyBy('id');return[$locked,$class,$inventory,$instances,$equipment,$catalog];}private function assertSynchronized(Character $character,$instances,$equipment,$catalog){$instanceRows=$equipment->groupBy('item_instance_id');foreach($equipment as $row){$instance=$instances->firstWhere('id',$row->item_instance_id);$item=$instance?$catalog->get($instance->item_id):null;if((int)$row->character_id!==(int)$character->id||!$instance||!$item||$instance->status!==ItemInstanceStatus::EQUIPPED||$instanceRows->get($row->item_instance_id)->count()!==1)throw new RuntimeException('Inconsistent character equipment state.');CharacterEquipmentSlot::assertValid($row->slot);$this->items->assertCompatible($item,$row->slot);}foreach($instances as $instance){$has=$instanceRows->has($instance->id);if(($instance->status===ItemInstanceStatus::EQUIPPED)!==$has)throw new RuntimeException('Inconsistent ItemInstance equipment state.');if($instance->status!==ItemInstanceStatus::AVAILABLE&&$instance->status!==ItemInstanceStatus::EQUIPPED)throw new RuntimeException('Unsupported ItemInstance status.');}}}
